/// Convert a `tree_sitter_language_pack::error::Error` error to a Rustler error string.
#[allow(dead_code)]
fn error_to_rustler_err(e: tree_sitter_language_pack::error::Error) -> String {
    e.to_string()
}

fn on_load(env: rustler::Env, _info: rustler::Term) -> bool {
    env.register::<LanguageRegistry>()
        .expect("Failed to register resource type LanguageRegistry");
    env.register::<DownloadManager>()
        .expect("Failed to register resource type DownloadManager");
    env.register::<Tree>().expect("Failed to register resource type Tree");
    env.register::<Language>()
        .expect("Failed to register resource type Language");
    env.register::<Parser>()
        .expect("Failed to register resource type Parser");
    true
}

rustler::init!("Elixir.TreeSitterLanguagePack.Native", load = on_load);
